class Solution:
    def numDistinct(self, s, t):
        dp = [0] * (len(t) + 1)
        dp[0] = 1
        for ch in s:
            for i in range(len(t) - 1, -1, -1):
                if ch == t[i]: dp[i + 1] += dp[i]
        return dp[-1]
```

